const AppleIcon = () => (
  <svg className="btn__icon" viewBox="0 0 14 17" fill="currentColor" aria-hidden="true">
    <path d="M11.76 8.9c-.02-1.96 1.6-2.9 1.67-2.94-.91-1.33-2.33-1.51-2.83-1.54-1.2-.12-2.35.7-2.96.7-.6 0-1.54-.68-2.54-.66C3.8 4.49 2.6 5.23 1.94 6.4.59 8.76 1.55 12.27 2.86 14.2c.65 1 1.41 2.1 2.42 2.06 1.35-.05 1.57-.73 2.96-.73s1.75.73 2.95.71c1.03-.02 1.71-1.01 2.36-2.01.77-1.17 1.09-2.27 1.11-2.33-.02 0-2.12-.82-2.9-3zm-2.78-5.58c.63-.77 1.06-1.81.94-2.88-.91.04-2 .6-2.65 1.37-.58.67-1.09 1.74-.9 2.76 1.01.08 2.05-.5 2.61-1.25z" />
  </svg>
)

export function Button({
  variant = 'primary',
  size = 'default',
  label,
  className = '',
  ...props
}) {
  const cls = ['btn', `btn--${variant}`, `btn--size-${size}`, className]
    .filter(Boolean)
    .join(' ')

  if (variant === 'skeleton') {
    return <span className={cls} role="status" aria-label="Loading" />
  }

  if (variant === 'apple-pay') {
    return (
      <button className={cls} type="button" {...props}>
        <AppleIcon />
        <span>Pay</span>
      </button>
    )
  }

  if (variant === 'payment') {
    return (
      <button className={cls} type="button" {...props}>
        <LockIcon />
        {label && <span>{label}</span>}
      </button>
    )
  }

  return (
    <button className={cls} type="button" {...props}>
      {label}
    </button>
  )
}
